%[text] # Chucktown UrgentCare Simulation with Reneging 
%[text] Savannah Jellings and Natalie Huey
%[text] April 22nd 2026
%[text] Collect statistics and plot histograms along the way.
PictureFolder = "Pictures";
mkdir(PictureFolder); %[output:711cf690]
%%
%[text] ## Set up
%[text] We'll measure time in hours
%[text] #### Patient arrival rate: 2 per hour
lambda = 2;
%[text] #### Departure (service) rate: 1 per 20 minutes, so 3 per hour
mu = 3;
%[text] #### Renege rate: 1 patient reneges every 15min, so 4 per hour
theta = 4;
%[text] #### Number of doctors:
s = 2;
%[text] Run many samples of the queue:
NumSamples = 50;
%[text] #### Each sample is run up to a maximum time, for us an 8 hour shift:
MaxTime = 8;
%[text] Make a log entry every so often, one per minute:
LogInterval = 1/60;
%%
%[text] ## M/M/1 Values with Reneging
%[text] #### Values of $P\_n$:
nMax = 50;
P = zeros([nMax+1, 1]);
P(1) = 1;
for j = 1:nMax
    if j == 1
       departure = mu;
    elseif j == 2
        departure = 2*mu;
    else
        departure = 2*mu + (j-2)*theta;
    end 
    P(1+j) = P(j) * lambda / (mu + (j-1)*theta);
    end
P0 = 1/sum(P);
P = P*P0;
%[text] #### Part 3.1) The rate balance equation for $P\_n$ in terms of $P\_0$ is $P\_n = \\frac{\\lambda^n}{\\mu(\\mu+\\theta)(\\mu+2\\theta)...(\\mu+(n-1)\\theta)} P\_0$, $n\\geq1$
%[text] #### Print out values of $P\_0$ to $P\_5$ from theory:
for j = 0:5 %[output:group:79feeb22]
    fprintf('P_%d = %f\n', j, P(j+1)); %[output:2ae7daad]
end %[output:group:79feeb22]
%[text] Compute $\\pi\_s$ from theory:
pi = (mu*P(2) + 2*mu*sum(P(3:end)))/lambda;
%[text] #### Part 3.2) I initiated $\\theta=1$ for the following computations:
%[text] **1)** $P\_0 = 0.455679$, $P\_1=0.303786$, $P\_2=0.151893$, $P\_3=0.060757$, $P\_4=0.020252$, $P\_5=0.005786$. Comparing against the vaules without reneging, $P\_0,P\_1,P\_2$ are all slightly larger but then $P\_3,P\_4,P\_5$ are all slightly smaller. It makes sense for the probability to decrease as the number of customers increases, since longer lines makes it more likely for customers to leave without being served.
%[text] **2)** The fraction of customers served without reneging is $\\pi\_s=0.8165$.
%%
%[text] ## Run simulation samples
%[text] This is the most time consuming calculation in the script, so let's put it in its own section.  That way, we can run it once, and more easily run the faster calculations multiple times as we add features to this script.
%[text] Reset the random number generator.  This causes MATLAB to use the same sequence of pseudo-random numbers each time you run the script, which means the results come out exactly the same.  This is a good idea for testing purposes.  Under other circumstances, you probably want the random numbers to be truly unpredictable and you wouldn't do this.
rng("default");
%[text] We'll store our queue simulation objects in this list.
QSamples = cell([NumSamples, 1]);
%[text] The statistics come out weird if the log interval is too short, because the log entries are not independent enough.  So the log interval should be long enough for several arrival and departure events happen.
for SampleNum = 1:NumSamples %[output:group:57558acc]
    if mod(SampleNum, 10) == 0
        fprintf("%d ", SampleNum); %[output:386e9974]
    end
    if mod(SampleNum, 100) == 0
        fprintf("\n");
    end
    q = ServiceQueueRenege( ...
        ArrivalRate=lambda, ...
        DepartureRate=mu, ...
        NumServers=s, ...
        RenegeRate=theta, ...
        LogInterval=LogInterval);
    q.schedule_event(Arrival(random(q.InterArrivalDist), Customer(1)));
    run_until(q, MaxTime);
    QSamples{SampleNum} = q;
end %[output:group:57558acc]
%%
%[text] ## Collect measurements of how many customers are in the system
%[text] Count how many customers are in the system at each log entry for each sample run.  There are two ways to do this.  You only have to do one of them.
%[text] ### Option one: Use a for loop.
%[text] #### Compute simulation number of patients in the system:
NumInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % Pull out samples of the number of customers in the queue system. Each
    % sample run of the queue results in a column of samples of customer
    % counts, because tables like q.Log allow easy extraction of whole
    % columns like this.
    NumInSystemSamples{SampleNum} = q.Log.NumWaiting + q.Log.NumInService;
end
%[text] #### Compute number of patients waiting:
NumWaitingSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    NumWaitingSamples{SampleNum} = q.Log.NumWaiting;
end
%[text] #### Compute the count of patients who have been served: 
CountServed = cell([NumSamples,1]);
for SampleNum = 1:NumSamples
    q= QSamples{SampleNum};
    CountServed{SampleNum} = numel(q.Served);
end
%[text] #### Compute the count of patients who reneged:
CountReneged = cell([NumSamples,1]);
for SampleNum = 1:NumSamples 
    q = QSamples{SampleNum};
    CountReneged{SampleNum} = numel(q.Reneged);
end
%[text] #### Compute $\\pi\_s$ from the simulation samples:
CountServed2 = vertcat(CountServed{:});
totalServed = sum(CountServed2);
totalReneged = sum(cellfun(@(q) numel(q.Reneged), QSamples));
pi_s_sim = totalServed / (totalServed + totalReneged);
fprintf("Simulated pi_s: %f\n", pi_s_sim); %[output:9a5d34f4]
%[text] ### Option two: Map a function over the cell array of ServiceQueue objects.
%[text] The `@(q) ...` expression is shorthand for a function that takes a `ServiceQueue` as input, names it `q`, and computes the sum of two columns from its log.  The `cellfun` function applies that function to each item in `QSamples`. The option `UniformOutput=false` tells `cellfun` to produce a cell array rather than a numerical array.
NumInSystemSamples = cellfun( ...
    @(q) q.Log.NumWaiting + q.Log.NumInService, ...
    QSamples, ...
    UniformOutput=false);
%[text] ## Join numbers from all sample runs.
%[text] `vertcat` is short for "vertical concatenate", meaning it joins a bunch of arrays vertically, which in this case results in one tall column.
NumInSystem = vertcat(NumInSystemSamples{:});

NumWaiting = vertcat(NumWaitingSamples{:});

CountReneged = vertcat(CountReneged{:});
%[text] MATLAB-ism: When you pull multiple items from a cell array, the result is a "comma-separated list" rather than some kind of array.  Thus, the above means
%[text] `NumInSystem = vertcat(NumInSystemSamples{1}, NumInSystemSamples{2}, ...)`
%[text] which concatenates all the columns of numbers in NumInSystemSamples into one long column.
%[text] This is roughly equivalent to "splatting" in Python, which looks like `f(*args)`.
%%
%[text] ## Pictures and stats for number of customers in system
%[text] #### Print out mean number of patients in the system:
meanNumInSystem = mean(NumInSystem);
fprintf("Mean number in system: %f\n", meanNumInSystem); %[output:953147fc]
%[text] #### Print out mean number of patients waiting: 
meanNumWaiting = mean(NumWaiting);
fprintf("Mean number waiting: %f\n", meanNumWaiting); %[output:39bd3dc4]
%[text] #### Print out mean count of customers that reneged:
meanReneged = mean(CountReneged);
fprintf("Mean Count of Customers thet Reneged: %f\n",meanReneged); %[output:9bc993f5]
%[text] Make a figure with one set of axes.
fig = figure(); %[output:4bfb110e]
t = tiledlayout(fig,1,1); %[output:4bfb110e]
ax = nexttile(t); %[output:4bfb110e]
%[text] MATLAB-ism: Once you've created a picture, you can use `hold` to cause further plotting functions to work with the same picture rather than create a new one.
hold(ax, "on"); %[output:4bfb110e]
%[text] Start with a histogram.  The result is an empirical PDF, that is, the area of the bar at horizontal index n is proportional to the fraction of samples for which there were n customers in the system.  The data for this histogram is counts of customers, which must all be whole numbers.  The option `BinMethod="integers"` means to use bins $(-0.5, 0.5), (0.5, 1.5), \\dots$ so that the height of the first bar is proportional to the count of 0s in the data, the height of the second bar is proportional to the count of 1s, etc. MATLAB can choose bins automatically, but since we know the data consists of whole numbers, it makes sense to specify this option so we get consistent results.
%[text] ## Histogram of Patients in the System:
h = histogram(ax, NumInSystem, Normalization="probability", BinMethod="integers"); %[output:4bfb110e]
%[text] Plot $(0, P\_0), (1, P\_1), \\dots$.  If all goes well, these dots should land close to the tops of the bars of the histogram.
plot(ax, 0:5, P(1:6), 'o', MarkerEdgeColor='k', MarkerFaceColor='r'); %[output:4bfb110e]
%[text] Add titles and labels and such.
title(ax, "Number of customers in the system"); %[output:4bfb110e]
xlabel(ax, "Count"); %[output:4bfb110e]
ylabel(ax, "Probability"); %[output:4bfb110e]
legend(ax, "simulation", "theory"); %[output:4bfb110e]
%[text] Set ranges on the axes. MATLAB's plotting functions do this automatically, but when you need to compare two sets of data, it's a good idea to use the same ranges on the two pictures.  To start, you can let MATLAB choose the ranges automatically, and just know that it might choose very different ranges for different sets of data.  Once you're certain the picture content is correct, choose an x range and a y range that gives good results for all sets of data.  The final choice of ranges is a matter of some trial and error.  You generally have to do these commands *after* calling `plot` and `histogram`.
%[text] This sets the vertical axis to go from $0$ to $0.2$.
ylim(ax, [0, 0.6]); %[output:4bfb110e]
%[text] This sets the horizontal axis to go from $-1$ to $21$.  The histogram will use bins $(-0.5, 0.5), (0.5, 1.5), \\dots$ so this leaves some visual breathing room on the left.
xlim(ax, [-1, 6]); %[output:4bfb110e]
%[text] MATLAB-ism: You have to wait a couple of seconds for those settings to take effect or `exportgraphics` will screw up the margins.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Number in system histogram.pdf"); %[output:4bfb110e]
exportgraphics(fig, PictureFolder + filesep + "Number in system histogram.svg"); %[output:4bfb110e]
%%
%[text] ## Histogram of patients waiting:
fig = figure(); %[output:72ff5c5a]
t = tiledlayout(fig,1,1); %[output:72ff5c5a]
ax = nexttile(t); %[output:72ff5c5a]
h = histogram(ax, NumWaiting, Normalization="probability", BinMethod="integers"); %[output:72ff5c5a]
title(ax, "Number of customers waiting"); %[output:72ff5c5a]
xlabel(ax, "Count"); %[output:72ff5c5a]
ylabel(ax, "Probability"); %[output:72ff5c5a]
%[text] Set ranges on the axes.
ylim(ax, [0, 1.0]); %[output:72ff5c5a]
xlim(ax, [-1, 20]); %[output:72ff5c5a]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:72ff5c5a]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:72ff5c5a]
%%
%[text] ## Histogram of the number of patients served:
fig = figure(); %[output:70fa38e6]
t = tiledlayout(fig,1,1); %[output:70fa38e6]
ax = nexttile(t); %[output:70fa38e6]
h = histogram(ax, CountServed2, Normalization="probability", BinMethod="integers"); %[output:70fa38e6]
title(ax, "Number of customers served per shift"); %[output:70fa38e6]
xlabel(ax, "Count"); %[output:70fa38e6]
ylabel(ax, "Probability"); %[output:70fa38e6]
%[text] Set ranges on the axes.
ylim(ax, [0, 0.3]); %[output:70fa38e6]
xlim(ax, [6, 25]); %[output:70fa38e6]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:70fa38e6]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:70fa38e6]
%%
%[text] ## Collect measurements of how long customers spend in the system
%[text] This is a rather different calculation because instead of looking at log entries for each sample `ServiceQueue`, we'll look at the list of served  customers in each sample `ServiceQueue`.
%[text] ### Option one: Use a for loop.
%[text] #### Calculate time patients spend in system:
TimeInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % The next command has many parts.
    %
    % q.Served is a row vector of all customers served in this particular
    % sample.
    % The ' on q.Served' transposes it to a column.
    %
    % The @(c) ... expression below says given a customer c, compute its
    % departure time minus its arrival time, which is how long c spent in
    % the system.
    %
    % cellfun(@(c) ..., q.Served') means to compute the time each customer
    % in q.Served spent in the system, and build a column vector of the
    % results.
    %
    % The column vector is stored in TimeInSystemSamples{SampleNum}.
    TimeInSystemSamples{SampleNum} = ...
        cellfun(@(c) c.DepartureTime - c.ArrivalTime, q.Served');
end
%[text] #### Calculate the time patients wait:
TimeWaitingSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    TimeWaitingSamples{SampleNum} = cellfun(@(c) c.BeginServiceTime - c.ArrivalTime, q.Served');
end
%[text] ### Option two: Use `cellfun` twice.
%[text] The outer call to `cellfun` means do something to each `ServiceQueue` object in `QSamples`.  The "something" it does is to look at each customer in the `ServiceQueue` object's list `q.Served` and compute the time it spent in the system.
TimeInSystemSamples = cellfun( ...
    @(q) cellfun(@(c) c.DepartureTime - c.ArrivalTime, q.Served'), ...
    QSamples, ...
    UniformOutput=false);
%[text] ### Join them all into one big column.
TimeInSystem = vertcat(TimeInSystemSamples{:});

TimeWaiting = vertcat(TimeWaitingSamples{:});

%[text] #### Calculate time patients are served by taking total waiting time and subtracting the time spent waiting:
TimeServed = TimeInSystem - TimeWaiting;
%%
%[text] ## Pictures and stats for time customers spend in the system
%[text] #### Print out mean time spent in the system and mean time spent waiting:
meanTimeInSystem = mean(TimeInSystem);
fprintf("Mean time in system: %f\n", meanTimeInSystem); %[output:0600f354]

meanTimeWaiting = mean(TimeWaiting);
fprintf("Mean time waiting: %f\n", meanTimeWaiting); %[output:9ad0ab25]
%[text] Make a figure with one set of axes.
fig = figure(); %[output:765b494b]
t = tiledlayout(fig,1,1); %[output:765b494b]
ax = nexttile(t); %[output:765b494b]
%[text] This time, the data is a list of real numbers, not integers.  The option `BinWidth=...` means to use bins of a particular width, and choose the left-most and right-most edges automatically.  Instead, you could specify the left-most and right-most edges explicitly.  For instance, using `BinEdges=0:0.5:60` means to use bins $(0, 0.5), (0.5, 1.0), \\dots$
%[text] ## Histogram for time patients spent in the system:
h = histogram(ax, TimeInSystem, Normalization="probability", BinWidth=5/60); %[output:765b494b]
%[text] Add titles and labels and such.
title(ax, "Time in the system"); %[output:765b494b]
xlabel(ax, "Time"); %[output:765b494b]
ylabel(ax, "Probability"); %[output:765b494b]
%[text] Set ranges on the axes.
ylim(ax, [0, 0.3]); %[output:765b494b]
xlim(ax, [0, 4]); %[output:765b494b]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:765b494b]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:765b494b]
%%
%[text] ## Histogram for time paatients spent waiting:
fig = figure(); %[output:5ff1b40d]
t = tiledlayout(fig,1,1); %[output:5ff1b40d]
ax = nexttile(t); %[output:5ff1b40d]
h = histogram(ax, TimeWaiting, Normalization="probability", BinWidth=5/60); %[output:5ff1b40d]
title(ax, "Time spent waiting"); %[output:5ff1b40d]
xlabel(ax, "Time"); %[output:5ff1b40d]
ylabel(ax, "Probability"); %[output:5ff1b40d]
%[text] Set ranges on the axes.
ylim(ax, [0, 1.0]); %[output:5ff1b40d]
xlim(ax, [0, 1.5]); %[output:5ff1b40d]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:5ff1b40d]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:5ff1b40d]
%%
%[text] ## Histogram for time it takes patients to be served:
fig = figure(); %[output:7cc1ef2a]
t = tiledlayout(fig,1,1); %[output:7cc1ef2a]
ax = nexttile(t); %[output:7cc1ef2a]
h = histogram(ax, TimeServed, Normalization="probability", BinWidth=5/60); %[output:7cc1ef2a]
title(ax, "Time Customers Spent Being Served"); %[output:7cc1ef2a]
xlabel(ax, "Time"); %[output:7cc1ef2a]
ylabel(ax, "Probability"); %[output:7cc1ef2a]
%[text] Set ranges on the axes.
ylim(ax, [0, 0.3]); %[output:7cc1ef2a]
xlim(ax, [0, 3]); %[output:7cc1ef2a]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:7cc1ef2a]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:7cc1ef2a]
%%
%[text] ## Histogram for number of patients who reneged:
fig = figure(); %[output:049bd602]
t = tiledlayout(fig,1,1); %[output:049bd602]
ax = nexttile(t); %[output:049bd602]
h = histogram(ax, CountReneged, Normalization="probability", BinMethod="integers"); %[output:049bd602]
title(ax, "Count of Customers that Renege"); %[output:049bd602]
xlabel(ax, "Count"); %[output:049bd602]
ylabel(ax, "Probability"); %[output:049bd602]
ylim(ax, [0 0.6]); %[output:049bd602]
xlim(ax,[-1 15]); %[output:049bd602]
%%
%[text] # Part 4:
%[text] **3)** The theoretical values of $P\_0,...,P\_5$ agree pretty well with the simulated values of $P\_0,...,P\_5$. On the histogram, each of the five red dots are very close to the simulation vaules as represented by the blue bars.
%[text] **5)** From the simulation, we get $L=0.593987$, $L\_q=0.131955$, $W=0.353286$, and $W\_q=0.038248$. We also get the simulated value $\\pi\_s=0.712468$, and the average count of customers that reneged is 4.52.
%[text] **7)** As one might expect, there are less customers being served in the reneging simulation compared to the baseline simulation. This makes sense, since people are leaving the queue without being served. Time spent waiting is also lower with reneging. Since there are less people waiting to be served, overall patients spend less time waiting. Building off of this, it also makes sense that with reneging the time a patient spends in system is lower overall than without reneging. The time customers spend being served is about the same between the two simulations, which makes sense because the doctor still takes 20 minutes to see a patient. The simulation values from the baseline are $L=1.697$, $L\_q=1.085$, $W=0.732$, and$W\_q=0.419$. The simulation values with reneging are $L=0.593987$, $L\_q=0.131955$, $W=0.353286$, and $W\_q=0.038248$. These values are a lot lower, which makes sense since the number of customers in the system and waiting are lower with reneging, and the time spent in the queue and waiting is also lower with reneging.

